import { IconZ } from "../Simple/Image";
import { priceFmt } from "../../utils/prices";
import { dateToMonthStr } from "../../utils/dates";
import "./ItemCardLeft.css";

import { Carousel, Badge } from "../../cdn";
import type { Item, Image } from "../../types";

export const ItemCardLeft = ({ item }: { item: Item }) => {
  const floorplans: Image[] = (item.floorplans || [])
    .map((x: Image) => {
      return { url: x.url } as Image; // discard caption for floorplans
    })
    .reverse();

  const imagesAndFloorplans: Image[] = (item.images || []).concat(floorplans);
  const N = imagesAndFloorplans.length;
  return (
    <>
      <Carousel interval={86400000} defaultActiveIndex={0}>
        {imagesAndFloorplans.map((im: Image, index: number) => (
          <Carousel.Item key={index}>
            <img
              loading="lazy"
              referrerPolicy="no-referrer"
              className="d-block"
              src={im.url}
              alt={"caption: " + im.caption}
            />
            <Carousel.Caption style={{ display: "flex", justifyContent: "center" }}>
              <p>
                <strong>{`${index + 1}/${N} `}</strong>
                {im.caption || ""}
              </p>
            </Carousel.Caption>
          </Carousel.Item>
        ))}
      </Carousel>

      <CaptionLine1 item={item} />
      {item.zoopla_est && <CaptionZooplaEstimate item={item} />}
      {item.zoopla_peak && <CaptionZooplaPeakEstimate item={item} />}
      {item.zoopla_rent_estimate && <CaptionZooplaRentEstimate item={item} />}
    </>
  );
};

const CaptionLine1 = ({ item }: { item: Item }) => {
  const itemPhotosUrl = `https://www.rightmove.co.uk/properties/${item.id}#/media?channel=${item.channel}`;

  const infoToClipboard = (_event: React.MouseEvent) => {
    // Facilitate copy/paste
    const lines: string[] = [
      ``,
      `  "${item.id}": {`,
      `    "zoopla_advert_id": null, "zoopla_uprn": null,`,
      `    "__address_r": "${item.address}",`,
      `    "notes": null, "size_sqm": null, "coordinates": null},`,
      ``,
    ];
    navigator.clipboard.writeText(lines.join("\n"));
  };

  return (
    <p className="x-caption-1">
      <span className="x-loop-index" onClick={infoToClipboard}>
        {item.loopIndex}
      </span>
      {item.sold_let && (
        <Badge text="dark" bg="warning" className="x-badge">
          {item.sold_let}
        </Badge>
      )}
      {item.is_new && (
        <Badge text="light" bg="success" className="x-badge">
          NEW
        </Badge>
      )}
      <a rel="noreferrer" target="_blank" href={itemPhotosUrl} style={{ textDecoration: "none" }}>
        {priceFmt(item.price)}
      </a>
    </p>
  );
};

const CaptionZooplaEstimate = ({ item }: { item: Item }) => {
  const url = `https://www.zoopla.co.uk/property/uprn/${item.zoopla_uprn}/`;

  return item.channel === "rent" ? (
    <p className="x-caption-2">
      <span className="x-manual-all">{diffPctFmt(item.price, item.zoopla_rent_estimate)}</span> on{" "}
      <a rel="noreferrer" target="_blank" href={url} className="x-manual-all">
        {priceFmt(item.zoopla_rent_estimate)}pm <IconZ style={{ verticalAlign: "unset" }} />
      </a>
    </p>
  ) : (
    <p className="x-caption-2">
      <span className="x-manual-all">{diffPctFmt(item.price, item.zoopla_est * 1000)}</span> on{" "}
      <a rel="noreferrer" target="_blank" href={url} className="x-manual-all">
        {priceFmt(item.zoopla_est * 1000)} <IconZ style={{ verticalAlign: "unset" }} />
      </a>
      {item.zoopla_estimate_date && <span> in {dateToMonthStr(item.zoopla_estimate_date)}</span>}
    </p>
  );
};

const CaptionZooplaPeakEstimate = ({ item }: { item: Item }) => {
  return item.channel === "rent" ? (
    <p className="x-caption-2">
      <span className="x-manual-all">{priceFmt(item.zoopla_est * 1000)}</span>
      {item.zoopla_estimate_date && <span> in {dateToMonthStr(item.zoopla_estimate_date)}</span>}
    </p>
  ) : (
    <p className="x-caption-2">
      <span className="x-manual-all">{diffPctFmt(item.price, item.zoopla_peak * 1000)}</span> on{" "}
      <span className="x-manual-all">{priceFmt(item.zoopla_peak * 1000)}</span> peak of{" "}
      <span className="x-manual-all">{item.zoopla_peak_date}</span>
    </p>
  );
};

const CaptionZooplaRentEstimate = ({ item }: { item: Item }) => {
  return item.channel === "rent" ? (
    <p className="x-caption-2">
      <span className="x-manual-all">{yieldPct(item.price / item.zoopla_est / 1000)}</span> rental
      yield
    </p>
  ) : (
    <p className="x-caption-2">
      <span className="x-manual-all">{yieldPct(item.zoopla_rent_estimate / item.price)}</span>{" "}
      rental yield at {priceFmt(item.zoopla_rent_estimate)}pm
    </p>
  );
};

/**
 *  Utils functions
 */
const diffPctFmt = (a: number, b: number) => {
  return new Intl.NumberFormat("en-GB", {
    style: "percent",
    signDisplay: "exceptZero",
    minimumFractionDigits: 1,
    maximumFractionDigits: 1,
  }).format((a - b) / b);
};
const yieldPct = (monthlyRatio: number) => {
  return new Intl.NumberFormat("en-GB", {
    style: "percent",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format((1 + monthlyRatio) ** 12 - 1);
};
export default ItemCardLeft;
