const DAY = 24 * 3600 * 1000;
let g_now = new Date();

export const updateAllRelativeTimestamps = () => {
  g_now = new Date();
  //console.log(`Refresh relative timestamps on ${g_now}`);
  document.querySelectorAll(".x-date-relative").forEach((element: Element) => {
    const elem = element as HTMLElement;
    if (elem.dataset.date === undefined) return; // can be too early
    const convertType = elem.dataset.convert;
    if (convertType === "days") {
      elem.innerText = dateToDays(elem.dataset.date);
    } else if (convertType === "hours") {
      elem.innerText = dateToHours(elem.dataset.date);
    } else if (convertType === "hours-negative") {
      elem.innerText = dateToHours(elem.dataset.date, true);
    }
  });
};

export const dateToStr = (dtStr: string) => {
  const dt = new Date(dtStr);
  let opts: Intl.DateTimeFormatOptions = { day: "numeric", month: "short", year: "numeric" };
  const dtDiff = g_now.valueOf() - dt.valueOf();
  if (dtDiff < 14 * DAY) {
    opts.weekday = "long";
  }
  if (dtDiff < 2 * DAY) {
    opts.hour = "numeric";
    opts.minute = "numeric";
  }
  return dt.toLocaleDateString("en-GB", opts);
};

export const dateToShortStr = (dtStr: string) => {
  const dt = new Date(dtStr);
  let opts: Intl.DateTimeFormatOptions = { day: "numeric", month: "short", year: "numeric" };
  return dt.toLocaleDateString("en-GB", opts);
};

export const dateToMonthStr = (dtStr: string) => {
  const dt = new Date(dtStr);
  let opts: Intl.DateTimeFormatOptions = { month: "short", year: "numeric" };
  return dt.toLocaleDateString("en-GB", opts);
};

export const dateToDays = (dtStr: string) => {
  const dt = new Date(dtStr);
  const dtDiff = g_now.valueOf() - dt.valueOf();
  const offsetDays = dtDiff / DAY;
  return offsetDays.toLocaleString("en-GB", { maximumFractionDigits: 1 });
};

export const dateToHours = (dtStr: string, invert = false) => {
  if (dtStr === undefined) return "";
  const dt = new Date(dtStr);
  const dtDiff = g_now.valueOf() - dt.valueOf();

  let offsetMinutes = (invert ? -dtDiff : dtDiff) / 60000;
  const signStr = offsetMinutes < 0 ? "-" : "";
  offsetMinutes = Math.abs(offsetMinutes);

  const h = Math.floor(offsetMinutes / 60);
  const m = Math.floor(offsetMinutes % 60);
  const mStr = m.toLocaleString("en-GB", {
    minimumIntegerDigits: 2,
  });
  return `${signStr}${h}h${mStr}m`;
};
