import { Form, Badge, CloseButton, Dropdown, DropdownButton, useState } from "../../cdn";
import "./CheckBox.css";

export const CheckBox = ({
  checkState,
  label,
}: {
  checkState: [boolean, (value: boolean) => void];
  label: string;
}) => {
  const [isApplied, setIsApplied] = checkState;

  return (
    <Form>
      <Form.Check
        type="switch"
        onChange={(e: React.ChangeEvent) => setIsApplied((e.target as HTMLInputElement).checked)}
        checked={isApplied}
      />
      <p>{label}</p>
    </Form>
  );
};

export const CheckBoxText = ({
  checkState,
  labelBefore,
  labelAfter,
  maxWidth = "3rem",
  textState,
}: {
  checkState: [boolean, (value: boolean) => void];
  labelBefore: string;
  labelAfter?: string;
  maxWidth: string;
  textState: [string, (value: string) => void];
}) => {
  const [isApplied, setIsApplied] = checkState;
  const [textValue, setTextValue] = textState;
  const onChangeText = (e: React.ChangeEvent) => {
    setTextValue((e.target as HTMLInputElement).value);
    setIsApplied(false);
  };
  const onKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === "Enter") {
      setIsApplied(true);
      event.preventDefault();
    } else {
      setIsApplied(false);
    }
  };

  return (
    <Form>
      <Form.Check
        type="switch"
        onChange={(e: React.ChangeEvent) => setIsApplied((e.target as HTMLInputElement).checked)}
        checked={isApplied}
      />
      <p>{labelBefore}</p>
      <Form.Control
        value={textValue}
        onChange={onChangeText}
        style={{ maxWidth: maxWidth }}
        onKeyDown={onKeyDown}
      />
      {labelAfter && <p>{labelAfter}</p>}
    </Form>
  );
};

export const SearchBox = ({
  label,
  maxWidth,
  addrState,
  priceState,
  agencyState,
  idState,
}: {
  label?: string;
  maxWidth: string;
  addrState: [string, (value: string) => void];
  priceState: [string, (value: string) => void];
  agencyState: [string, (value: string) => void];
  idState: [string, (value: string) => void];
}) => {
  const [tmpValue, setTmpValue] = useState("");
  const [addrValue, setAddrValue] = addrState;
  const [priceValue, setPriceValue] = priceState;
  const [agencyValue, setAgencyValue] = agencyState;
  const [idFilterValue, setIdFilterValue] = idState;

  const saveValue = (eventKey: string | null, value = "") => {
    value = value.trim();
    if (eventKey === "address") setAddrValue(value);
    else if (eventKey === "price") setPriceValue(value);
    else if (eventKey === "agency") setAgencyValue(value);
    else if (eventKey === "id") setIdFilterValue(value);
  };

  const onChangeText = (e: React.ChangeEvent) => {
    setTmpValue((e.target as HTMLInputElement).value);
  };
  const onKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === "Enter") {
      event.preventDefault();
      saveValue("address", tmpValue);
    }
  };

  return (
    <>
      <Form>
        {label && <p>{label}</p>}
        <Form.Control
          value={tmpValue}
          onChange={onChangeText}
          style={{ maxWidth: maxWidth }}
          onKeyDown={onKeyDown}
        />
        <DropdownButton
          title="Search"
          variant="success"
          id="x-btn-search"
          onSelect={(eventKey: string | null) => saveValue(eventKey, tmpValue)}
        >
          <Dropdown.Item eventKey="address">in Address</Dropdown.Item>
          <Dropdown.Item eventKey="price">in Price</Dropdown.Item>
          <Dropdown.Item eventKey="agency">in Agency</Dropdown.Item>
          <Dropdown.Item eventKey="id">in ID</Dropdown.Item>
        </DropdownButton>
      </Form>

      {addrValue && (
        <Badge pill bg="primary">
          <CloseButton onClick={() => saveValue("address")} variant="white" />
          <span>{addrValue}</span>
        </Badge>
      )}
      {priceValue && (
        <Badge pill bg="info" text="dark">
          <CloseButton onClick={() => saveValue("price")} />
          <span>{priceValue}</span>
        </Badge>
      )}
      {agencyValue && (
        <Badge pill bg="light" text="dark">
          <CloseButton onClick={() => saveValue("agency")} />
          <span>{agencyValue}</span>
        </Badge>
      )}
      {idFilterValue && (
        <Badge pill bg="dark">
          <CloseButton onClick={() => saveValue("id")} variant="white" />
          <span>{idFilterValue}</span>
        </Badge>
      )}
    </>
  );
};
